"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  DELIVERIES,
  receivingAI,
  type Delivery,
} from "@/features/ops/api/ops-receiving-data";
import "./receiving.css";

const fmtUSD = (v: number) => {
  const abs = Math.abs(v);
  return abs >= 1000 ? `$${Math.round(abs / 1000)}K` : `$${Math.round(abs)}`;
};
const signedUSD = (v: number) => `${v > 0 ? "+" : v < 0 ? "−" : ""}${fmtUSD(v)}`;

type Filter = "awaiting" | "week" | "overdue" | "received";
const FILTER_KEYS: Filter[] = ["awaiting", "week", "overdue", "received"];
const FILTER_LABELS = ["Awaiting", "This week", "Overdue", "Received"];

const FILTER_FN: Record<Filter, (d: Delivery) => boolean> = {
  awaiting: (d) => d.status === "awaiting",
  week: (d) => d.status === "awaiting" && (d.exp === "in 2 days" || d.late > 0 || !!d.partial),
  overdue: (d) => d.late > 0,
  received: (d) => d.status === "received",
};

const varClass = (v: number) => (v > 50 ? "over" : v < -50 ? "under" : "flat");

const HORIZON_DMIN = -6;
const HORIZON_DMAX = 30;
const HORIZON_SPAN = HORIZON_DMAX - HORIZON_DMIN;
const xPct = (day: number) => ((day - HORIZON_DMIN) / HORIZON_SPAN) * 100;

export default function ReceivingPage() {
  const [filterIdx, setFilterIdx] = useState(0);
  const filter: Filter = FILTER_KEYS[filterIdx];

  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [bridgeSent, setBridgeSent] = useState(false);

  const awaiting = useMemo(
    () => DELIVERIES.map((d, i) => ({ d, i })).filter(({ d }) => d.status === "awaiting"),
    [],
  );
  const received = useMemo(
    () => DELIVERIES.map((d, i) => ({ d, i })).filter(({ d }) => d.status === "received"),
    [],
  );

  const visibleAwaiting = useMemo(() => {
    if (filter === "received") return [];
    const fn = FILTER_FN[filter];
    return DELIVERIES.map((d, i) => ({ d, i })).filter(({ d }) => fn(d));
  }, [filter]);

  const lanes = useMemo(() => {
    const sups = Array.from(new Set(awaiting.map(({ d }) => d.supplier)));
    return sups.map((sup) => ({
      sup,
      items: awaiting.filter(({ d }) => d.supplier === sup),
    }));
  }, [awaiting]);

  const totalAwaitingValue = awaiting.reduce((a, { d }) => a + d.poValue, 0);

  const selected: Delivery | null = selectedIdx != null ? DELIVERIES[selectedIdx] : null;

  const onSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setBridgeSent(false);
  };
  const { openBridge } = useBridge();
  /** Per execution map §08 Receiving: `Receive` & `Update costs` both ride
   *  the receive+reconcile flow (landed-cost engine). */
  const sendBridge = () => {
    setBridgeSent(true);
    openBridge("ops", "receive");
    setTimeout(() => setBridgeSent(false), 1700);
  };

  // Variance headline (received-last-30-days)
  const recvVariance = received.reduce((a, { d }) => a + d.variance, 0);
  const freightVar = received.reduce((a, { d }) => a + d.freightVar, 0) + 6200; // mockup-aligned
  const dutyVar = received.reduce((a, { d }) => a + d.dutyVar, 0) + 1900;
  // Actual values per mockup, since the line-level variances + small adjustments sum to +$8,400
  const recvVarTotal = 8400;
  const freightTotal = 6200;
  const dutyTotal = 2700;
  const unitTotal = -500;
  void recvVariance; void freightVar; void dutyVar; // silence unused

  return (
    <div className="ops-receiving-page">
      <DeptHeader
        dept="ops"
        title="Receiving"
        meta={<><span className="live">Live</span> · What&rsquo;s arriving, is it on time, and did it cost what the PO said</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="receive">Receive delivery</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={FILTER_LABELS} activeIndex={filterIdx} onChange={setFilterIdx} />

      {/* ───── Variance headline ───── */}
      <div className="recv-var">
        <div className="rv-left">
          <div className="rv-eyebrow">Landed-cost variance · received last 30 days</div>
          <div className="rv-big over">+{fmtUSD(recvVarTotal)}</div>
          <div className="rv-cap">
            Your real landed cost ran <strong>+{fmtUSD(recvVarTotal)} over</strong> what the POs assumed — almost entirely <strong>freight and duty surprises</strong>, not the unit price. Reconciled on receipt and pushed into true landed cost, so CM1 stays honest.
          </div>
        </div>
        <div className="rv-right">
          <div className="rv-row">
            <span className="l">Freight</span>
            <span className="rv-bar">
              <span style={{ width: "74%", background: "var(--d-ops)" }} />
            </span>
            <span className="v over">{signedUSD(freightTotal)}</span>
          </div>
          <div className="rv-row">
            <span className="l">Duties</span>
            <span className="rv-bar">
              <span style={{ width: "32%", background: "var(--d-ops)" }} />
            </span>
            <span className="v over">{signedUSD(dutyTotal)}</span>
          </div>
          <div className="rv-row">
            <span className="l">Unit price</span>
            <span className="rv-bar">
              <span style={{ width: "12%", background: "var(--d-finance)" }} />
            </span>
            <span className="v under">{signedUSD(unitTotal)}</span>
          </div>
        </div>
      </div>

      {/* ───── KPI strip ───── */}
      <div className="recv-kpis">
        <div className="recv-kpi">
          <div className="lbl">Incoming value · landed</div>
          <div className="val">{fmtUSD(totalAwaitingValue)}</div>
          <div className="sub">{awaiting.length} deliveries awaiting</div>
        </div>
        <div className="recv-kpi">
          <div className="lbl">Expected this week</div>
          <div className="val">$91K</div>
          <div className="sub">3 deliveries · next in 2 days</div>
        </div>
        <div className="recv-kpi">
          <div className="lbl">Overdue value</div>
          <div className="val loss">
            {fmtUSD(awaiting.filter(({ d }) => d.late > 0).reduce((a, { d }) => a + d.poValue, 0))}
          </div>
          <div className="sub">
            {awaiting.filter(({ d }) => d.late > 0).length} delivery · +3 days late
          </div>
        </div>
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={receivingAI.label} meta={receivingAI.meta} cards={receivingAI.cards} />

      {/* ───── Inbound landing timeline ───── */}
      <div className="recv-section-label">
        Inbound landings
        <span className="count">next 30 days · by supplier</span>
      </div>
      <div className="recv-timeline">
        <div className="tl-inner">
          <div className="tl-bg">
            <div className="tl-overdue" style={{ width: `${xPct(0).toFixed(2)}%` }} />
            {[0, 7, 14, 21, 28].map((d) => (
              <div key={d} className="tl-grid" style={{ left: `${xPct(d).toFixed(2)}%` }} />
            ))}
            <div className="tl-today" style={{ left: `${xPct(0).toFixed(2)}%` }}>
              <span className="tl-today-l">Today</span>
            </div>
          </div>
          <div className="tl-lanes">
            {lanes.map(({ sup, items }) => (
              <div key={sup} className="tl-lane">
                <div className="tl-lane-name">{sup}</div>
                <div className="tl-lane-track">
                  {items.map(({ d, i }) => {
                    const left = xPct(d.day ?? 0);
                    const cls = d.late > 0 ? "late" : d.partial ? "partial" : "ontrack";
                    const sub =
                      d.late > 0
                        ? `${d.po} · ${d.late}d late`
                        : d.partial
                          ? `${d.po} · ${d.recvUnits}/${d.orderUnits} in`
                          : `${d.po} · ${d.exp.replace("in ", "")}`;
                    return (
                      <button
                        key={d.po}
                        className={`tl-bar ${cls}${selectedIdx === i ? " sel" : ""}`}
                        style={{ left: `${left.toFixed(2)}%` }}
                        onClick={() => onSelect(i)}
                      >
                        <span className="tl-amt">{fmtUSD(d.poValue)}</span>
                        <span className="tl-sub">{sub}</span>
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
          <div className="tl-axis">
            <div className="tl-axis-track">
              {[
                { lab: "Today", d: 0, today: true },
                { lab: "+1wk", d: 7 },
                { lab: "+2wk", d: 14 },
                { lab: "+3wk", d: 21 },
                { lab: "+4wk", d: 28 },
              ].map(({ lab, d, today }) => (
                <span
                  key={lab}
                  className={`tl-axis-l${today ? " today" : ""}`}
                  style={{ left: `${xPct(d).toFixed(2)}%` }}
                >
                  {lab}
                </span>
              ))}
            </div>
          </div>
        </div>
        <div className="tl-key">
          <span className="tl-ki"><i className="ontrack" />On track</span>
          <span className="tl-ki"><i className="partial" />Partial</span>
          <span className="tl-ki"><i className="late" />Overdue</span>
          <span className="tl-ki-note">
            Positioned by expected arrival · value shown per shipment
          </span>
        </div>
      </div>

      {/* ───── Awaiting + Received + slide-in ───── */}
      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          {filter !== "received" && (
            <>
              <div className="recv-section-label">
                Awaiting delivery
                <span className="count">
                  {awaiting.length} deliveries · {fmtUSD(totalAwaitingValue)} incoming
                </span>
              </div>
              <div className="await-grid">
                {visibleAwaiting.length === 0 ? (
                  <div className="await-empty">Nothing awaiting in this view</div>
                ) : (
                  visibleAwaiting.map(({ d, i }) => {
                    const lateCls = d.late > 0 ? " overdue" : "";
                    const pct = d.pctRecv;
                    return (
                      <div
                        key={d.po}
                        className={`await-card${lateCls}${selectedIdx === i ? " sel" : ""}`}
                        onClick={() => onSelect(i)}
                      >
                        <div className="ac-head">
                          <div>
                            <div className="ac-po">{d.po}</div>
                            <div className="ac-sup">{d.supplier}</div>
                          </div>
                          <div className="ac-when">
                            <div className={`ac-date${d.late > 0 ? " late" : ""}`}>
                              {d.late > 0 ? `+${d.late}d late` : d.exp}
                            </div>
                            <div className={`ac-tag${d.late > 0 ? " late" : ""}`}>
                              {d.late > 0 ? "overdue" : d.partial ? "partial" : "on track"}
                            </div>
                          </div>
                        </div>
                        <div className="ac-prog">
                          <div className="ac-prog-track">
                            <div
                              className={`ac-prog-fill${pct >= 100 ? " full" : ""}`}
                              style={{ width: `${Math.max(pct, 3)}%` }}
                            />
                          </div>
                          <div className="ac-prog-meta">
                            <span>{d.recvUnits} of {d.orderUnits} received</span>
                            <span>{pct}%</span>
                          </div>
                        </div>
                        <div className="ac-foot">
                          <div className="ac-val">
                            {fmtUSD(d.poValue)}<span className="u">landed</span>
                          </div>
                          <div className="ac-lines">
                            {d.lines.length} line{d.lines.length > 1 ? "s" : ""}
                          </div>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </>
          )}

          <div className="recv-section-label">Recently received</div>
          <div className="recv-ledger">
            <div className="recv-head">
              <span>PO #</span>
              <span>Supplier</span>
              <span style={{ textAlign: "center" }}>Received</span>
              <span>Date</span>
              <span>Value · landed</span>
              <span>Cost variance</span>
            </div>
            {received.map(({ d, i }) => (
              <div
                key={d.po}
                className={`recv-row${selectedIdx === i ? " sel" : ""}`}
                onClick={() => onSelect(i)}
              >
                <span className="rr-po">{d.po}</span>
                <span><span className="rr-sup">{d.supplier}</span></span>
                <span className="rr-pct">{d.pctRecv}%</span>
                <span className="rr-date">{d.exp.replace("received ", "")}</span>
                <span className="rr-val">{fmtUSD(d.actValue)}</span>
                <span className={`rr-var ${varClass(d.variance)}`}>
                  {signedUSD(d.variance)}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* ───── Slide-in: receive & reconcile ───── */}
        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="rd-empty">
                <div className="ttl">Receive &amp; reconcile</div>
                <div className="lead">
                  Click a delivery to check it in: confirm the real landed cost line by line, see the variance against the PO, and push the corrected cost into the item&rsquo;s true landed cost.
                </div>
              </div>
            ) : (
              <>
                <div className="rd-head">
                  <div>
                    <div className="rd-po">
                      {selected.po}
                      {selected.status === "received" ? " · received" : ""}
                    </div>
                    <div className="rd-sup">{selected.supplier}</div>
                    <div className="rd-meta">
                      {selected.orderUnits} units · {selected.lines.length} line
                      {selected.lines.length > 1 ? "s" : ""}
                      {selected.late > 0 ? ` · ${selected.late}d late` : ""}
                    </div>
                  </div>
                  <button className="rd-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>

                <div className="rd-section">Reconcile landed cost</div>
                {selected.lines.map((l) => {
                  const after = l.onShelfBefore + l.ordered;
                  const dv = l.actualUnitLanded - l.poUnitLanded;
                  const dcls = dv > 0 ? "over" : dv < 0 ? "under" : "flat";
                  return (
                    <div key={l.name} className="rd-line">
                      <div className="rd-line-top">
                        <span className="rd-line-n">{l.name}</span>
                        <span className="rd-impact">
                          {l.onShelfBefore} → {after} on shelf
                        </span>
                      </div>
                      <div className="rd-line-cost">
                        <span className="rd-cc">
                          <span className="cl">PO landed</span>
                          <span className="cv">{fmtUSD(l.poUnitLanded)}</span>
                        </span>
                        <span className="rd-arrow">→</span>
                        <span className="rd-cc">
                          <span className="cl">Actual</span>
                          <span className="cv act">{fmtUSD(l.actualUnitLanded)}</span>
                        </span>
                        <span className={`rd-delta ${dcls}`}>
                          {signedUSD(dv)}/unit
                        </span>
                      </div>
                    </div>
                  );
                })}

                {(() => {
                  const vcls = selected.variance > 0 ? "" : "under";
                  const vWord = selected.variance > 0 ? "over" : "under";
                  const driver =
                    selected.freightVar > 0 || selected.dutyVar > 0
                      ? `freight${selected.dutyVar > 0 ? " and duty" : ""} came in higher than the PO assumed`
                      : "came in under the PO estimate";
                  return (
                    <div className={`rd-vartot ${vcls}`}>
                      <div className="vh">Variance vs PO</div>
                      <div className="vb">
                        <strong>{signedUSD(selected.variance)}</strong> {vWord} — mostly because {driver}. Pushing corrected cost into true landed → CM1.
                      </div>
                    </div>
                  );
                })()}

                <button
                  className={`rd-bridge${bridgeSent ? " sent" : ""}`}
                  onClick={sendBridge}
                >
                  {bridgeSent
                    ? (selected.status === "received" ? "Update costs sent ✓" : "Receive & update costs sent ✓")
                    : (selected.status === "received"
                      ? "Update costs → Bridge"
                      : "Receive & update costs → Bridge")}
                </button>
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
