/**
 * Mock data for the Operations · Receiving sub-page.
 *
 * Each delivery has lines [name, ordered, receivedSoFar, onShelfBefore,
 * poUnitLanded, actualUnitLanded] plus freight/duty variances. Computed:
 *   poValue   — sum(ordered × poUnitLanded)
 *   actValue  — sum(ordered × actualUnitLanded) + freightVar + dutyVar
 *   variance  — actValue − poValue
 *   pctRecv   — pct received so far
 */

export type RecvStatus = "awaiting" | "received";

export interface RecvLineRaw {
  name: string;
  ordered: number;
  receivedSoFar: number;
  onShelfBefore: number;
  /** USD landed per unit, as captured at PO time */
  poUnitLanded: number;
  /** USD landed per unit, as measured at receipt */
  actualUnitLanded: number;
}

export interface DeliveryRaw {
  po: string;
  supplier: string;
  exp: string;
  late: number;
  status: RecvStatus;
  /** Day offset from today (−3 = 3 days overdue, +2 = lands in 2 days) — only for awaiting */
  day?: number;
  partial?: boolean;
  pct?: number;
  lines: RecvLineRaw[];
  /** USD variance on freight (positive = over PO) */
  freightVar: number;
  /** USD variance on duty (positive = over PO) */
  dutyVar: number;
}

export interface Delivery extends DeliveryRaw {
  poValue: number;
  actValue: number;
  variance: number;
  recvUnits: number;
  orderUnits: number;
  pctRecv: number;
}

