export const DELIVERIES: Delivery[] = RAW.map((d) => {
  const poValue = d.lines.reduce((a, l) => a + l.ordered * l.poUnitLanded, 0);
  const actValue =
    d.lines.reduce((a, l) => a + l.ordered * l.actualUnitLanded, 0) +
    (d.freightVar || 0) +
    (d.dutyVar || 0);
  const variance = actValue - poValue;
  const recvUnits = d.lines.reduce((a, l) => a + l.receivedSoFar, 0);
  const orderUnits = d.lines.reduce((a, l) => a + l.ordered, 0);
  const pctRecv = d.pct ?? Math.round((recvUnits / orderUnits) * 100);
  return { ...d, poValue, actValue, variance, recvUnits, orderUnits, pctRecv };
});

